parameters.new_string:
/**
 * User notification preferences model.
 *
 * Controls how and when users receive notifications across multiple channels.
 *
 * DECISION CHANGE (Agent 9): The original model (Agent 3) assumed email as the
 * only notification channel. With SMS (Agent 8) and webhook (Agent 6) adapters
 * now available, this model has been refactored to support per-channel preferences.
 * The `sms` and `webhook` fields are optional on `UserPreferences` to preserve
 * backward compatibility with existing records that only have `email`.
 */

import type { NotificationType } from './notification.js';

/**
 * Notification categories that group related notification types.
 * Users subscribe/unsubscribe at the category level.
 */
export type NotificationCategory = 'orders' | 'account' | 'system';

/**
 * How frequently email notifications are delivered.
 * - 'immediate': send as soon as the event occurs
 * - 'daily-digest': batch into a daily summary (not yet implemented)
 * - 'weekly-digest': batch into a weekly summary (not yet implemented)
 * - 'none': do not send email notifications
 */
export type EmailFrequency = 'immediate' | 'daily-digest' | 'weekly-digest' | 'none';

/**
 * Base channel preferences shared by all notification channels.
 */
export interface ChannelPreferences {
  /** Master switch for this channel */
  enabled: boolean;
  /** Per-category opt-in/out */
  categories: Record<NotificationCategory, boolean>;
}

/**
 * Email-specific notification preferences.
 * Extends base channel preferences with email-specific frequency setting.
 */
export interface EmailPreferences extends ChannelPreferences {
  /** Delivery frequency (email-specific) */
  frequency: EmailFrequency;
}

/**
 * SMS notification preferences.
 */
export interface SmsPreferences extends ChannelPreferences {}

/**
 * Webhook notification preferences.
 */
export interface WebhookPreferences extends ChannelPreferences {}

/**
 * Full user preferences record.
 *
 * `sms` and `webhook` are optional for backward compatibility — existing
 * preferences records that predate multi-channel support will only have `email`.
 * Missing channel preferences are treated as "use defaults" (all enabled).
 */
export interface UserPreferences {
  id: string;
  userId: string;
  email: EmailPreferences;
  sms?: SmsPreferences;
  webhook?: WebhookPreferences;
  createdAt: Date;
  updatedAt: Date;
}

/**
 * Input for updating email preferences. All fields optional.
 */
export interface UpdateEmailPreferencesInput {
  enabled?: boolean;
  frequency?: EmailFrequency;
  categories?: Partial<Record<NotificationCategory, boolean>>;
}

/**
 * Input for updating SMS preferences. All fields optional.
 */
export interface UpdateSmsPreferencesInput {
  enabled?: boolean;
  categories?: Partial<Record<NotificationCategory, boolean>>;
}

/**
 * Input for updating webhook preferences. All fields optional.
 */
export interface UpdateWebhookPreferencesInput {
  enabled?: boolean;
  categories?: Partial<Record<NotificationCategory, boolean>>;
}

/**
 * Map a NotificationType to its category for preference lookup.
 */
const NOTIFICATION_TYPE_CATEGORY: Record<NotificationType, NotificationCategory> = {
  'order-confirmation': 'orders',
  'order-status-update': 'orders',
