/**
 * Preferences service — business logic for user notification preferences.
 *
 * Manages user notification settings across all channels (email, SMS, webhook)
 * and provides a query interface for the NotificationService to check before sending.
 *
 * DECISION CHANGE (Agent 9): Extended from email-only (Agent 3) to support
 * per-channel preferences for email, SMS, and webhook. Missing channel
 * preferences on existing records are treated as "use defaults" (all enabled).
 *
 * Depends on:
 * - UserPreferencesRepository (data layer) for persistence
 */

import type {
  UserPreferences,
  UpdateEmailPreferencesInput,
  UpdateSmsPreferencesInput,
  UpdateWebhookPreferencesInput,
  ChannelPreferences,
} from '../models/user-preferences.js';
import {
  createDefaultEmailPreferences,
  createDefaultSmsPreferences,
  createDefaultWebhookPreferences,
  getCategoryForType,
} from '../models/user-preferences.js';
import type { NotificationType, NotificationChannel } from '../models/notification.js';
import type { UserPreferencesRepository } from '../repositories/user-preferences.repository.js';
import { Logger } from '../utils/logger.js';

let nextId = 1;

function generateId(): string {
  return `pref-${String(nextId++).padStart(4, '0')}`;
}

/** Reset ID counter — for testing only. */
export function resetPreferencesIdCounter(): void {
  nextId = 1;
}

export class PreferencesService {
  private logger = new Logger('PreferencesService');

  constructor(private preferencesRepository: UserPreferencesRepository) {}

  /**
   * Get preferences for a user. Returns undefined if none exist.
   */
  getPreferences(userId: string): UserPreferences | undefined {
    return this.preferencesRepository.findByUserId(userId);
  }

  /**
   * Get preferences for a user, creating defaults if none exist.
   */
  getOrCreatePreferences(userId: string): UserPreferences {
    const existing = this.preferencesRepository.findByUserId(userId);
    if (existing) {
      return existing;
    }

    this.logger.info(`Creating default preferences for user: ${userId}`);
    const now = new Date();
    const prefs: UserPreferences = {
      id: generateId(),
      userId,
      email: createDefaultEmailPreferences(),
      sms: createDefaultSmsPreferences(),
      webhook: createDefaultWebhookPreferences(),
      createdAt: now,
      updatedAt: now,
    };

    this.preferencesRepository.save(prefs);
    return prefs;
  }

  /**
   * Update a user's email notification preferences.
   */
  updateEmailPreferences(
    userId: string,
    input: UpdateEmailPreferencesInput,
  ): UserPreferences {
    this.logger.info(`Updating email preferences for user: ${userId}`);

    const prefs = this.getOrCreatePreferences(userId);
    const updatedEmail = { ...prefs.email };

    if (input.enabled !== undefined) {
      updatedEmail.enabled = input.enabled;
    }
    if (input.frequency !== undefined) {
      updatedEmail.frequency = input.frequency;
    }
    if (input.categories) {
      updatedEmail.categories = {
        ...updatedEmail.categories,
        ...input.categories,
      };
    }

    return this.preferencesRepository.update(prefs.id, {
      email: updatedEmail,
      updatedAt: new Date(),
    });
  }

  /**
   * Update a user's SMS notification preferences.
   */
  updateSmsPreferences(
    userId: string,
    input: UpdateSmsPreferencesInput,
  ): UserPreferences {
    this.logger.info(`Updating SMS preferences for user: ${userId}`);

    const prefs = this.getOrCreatePreferences(userId);
    const updatedSms = { ...(prefs.sms ?? createDefaultSmsPreferences()) };

    if (input.enabled !== undefined) {
      updatedSms.enabled = input.enabled;
    }
    if (input.categories) {
      updatedSms.categories = {
        ...updatedSms.categories,
        ...input.categories,
      };
    }

    return this.preferencesRepository.update(prefs.id, {
      sms: updatedSms,
      updatedAt: new Date(),
    });
  }

  /**
   * Update a user's webhook notification preferences.
   */
  updateWebhookPreferences(
    userId: string,
    input: UpdateWebhookPreferencesInput,
  ): UserPreferences {
    this.logger.info(`Updating webhook preferences for user: ${userId}`);

    const prefs = this.getOrCreatePreferences(userId);
    const updatedWebhook = { ...(prefs.webhook ?? createDefaultWebhookPreferences()) };

    if (input.enabled !== undefined) {
      updatedWebhook.enabled = input.enabled;
    }
    if (input.categories) {
      updatedWebhook.categories = {
        ...updatedWebhook.categories,
        ...input.categories,
      };
    }

    return this.preferencesRepository.update(prefs.id, {
      webhook: updatedWebhook,
      updatedAt: new Date(),
    });
  }

  /**
   * Check whether a notification should be sent to a user.
   *
   * Returns true if the user has not opted out of the given
   * notification type on the given channel. If no preferences
   * exist for the user, defaults to allowing the notification.
   *
   * For channels with no saved preferences (e.g., legacy records
   * that only have email), defaults to allowing the notification.
   */
  shouldNotify(
    userId: string,
    notificationType: NotificationType,
    channel: NotificationChannel,
  ): boolean {
    const prefs = this.preferencesRepository.findByUserId(userId);

    // No preferences saved → allow all notifications (default opt-in)
    if (!prefs) {
      return true;
    }

    if (channel === 'email') {
      if (!prefs.email.enabled) {
        return false;
      }
      if (prefs.email.frequency === 'none') {
        return false;
      }
      const category = getCategoryForType(notificationType);
      return prefs.email.categories[category];
    }

    if (channel === 'sms') {
      // No SMS preferences saved (legacy record) → allow by default
      if (!prefs.sms) {
        return true;
      }
      return this.checkChannelPreferences(prefs.sms, notificationType);
    }

    if (channel === 'webhook') {
      // No webhook preferences saved (legacy record) → allow by default
      if (!prefs.webhook) {
        return true;
      }
      return this.checkChannelPreferences(prefs.webhook, notificationType);
    }

    // Unknown channel (e.g., in-app) — allow by default
    return true;
  }

  /**
   * Check base channel preferences (enabled + category).
   */
  private checkChannelPreferences(
    channelPrefs: ChannelPreferences,
    notificationType: NotificationType,
  ): boolean {
    if (!channelPrefs.enabled) {
      return false;
    }
    const category = getCategoryForType(notificationType);
    return channelPrefs.categories[category];
  }

  /**
   * Delete preferences for a user.
   */
  deletePreferences(userId: string): boolean {
    const prefs = this.preferencesRepository.findByUserId(userId);
    if (!prefs) {
      return false;
    }
    return this.preferencesRepository.delete(prefs.id);
  }
}

