import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { UserPreferencesRepository } from '../../src/repositories/user-preferences.repository.js';
import {
  PreferencesService,
  resetPreferencesIdCounter,
} from '../../src/services/preferences.service.js';

describe('PreferencesService', () => {
  let db: Database;
  let repo: UserPreferencesRepository;
  let service: PreferencesService;

  beforeEach(() => {
    db = new Database();
    repo = new UserPreferencesRepository(db);
    service = new PreferencesService(repo);
    resetPreferencesIdCounter();
  });

  describe('getPreferences', () => {
    it('should return undefined when no preferences exist', () => {
      expect(service.getPreferences('user-1')).toBeUndefined();
    });

    it('should return existing preferences', () => {
      service.getOrCreatePreferences('user-1');
      const prefs = service.getPreferences('user-1');
      expect(prefs).toBeDefined();
      expect(prefs!.userId).toBe('user-1');
    });
  });

  describe('getOrCreatePreferences', () => {
    it('should create default preferences for new user', () => {
      const prefs = service.getOrCreatePreferences('user-1');

      expect(prefs.id).toBe('pref-0001');
      expect(prefs.userId).toBe('user-1');
      expect(prefs.email.enabled).toBe(true);
      expect(prefs.email.frequency).toBe('immediate');
      expect(prefs.email.categories.orders).toBe(true);
      expect(prefs.email.categories.account).toBe(true);
      expect(prefs.email.categories.system).toBe(true);
    });

    it('should create default SMS preferences for new user', () => {
      const prefs = service.getOrCreatePreferences('user-1');

      expect(prefs.sms).toBeDefined();
      expect(prefs.sms!.enabled).toBe(true);
      expect(prefs.sms!.categories.orders).toBe(true);
      expect(prefs.sms!.categories.account).toBe(true);
      expect(prefs.sms!.categories.system).toBe(true);
    });

    it('should create default webhook preferences for new user', () => {
      const prefs = service.getOrCreatePreferences('user-1');

      expect(prefs.webhook).toBeDefined();
      expect(prefs.webhook!.enabled).toBe(true);
      expect(prefs.webhook!.categories.orders).toBe(true);
      expect(prefs.webhook!.categories.account).toBe(true);
      expect(prefs.webhook!.categories.system).toBe(true);
    });

    it('should return existing preferences without creating duplicates', () => {
      const first = service.getOrCreatePreferences('user-1');
      const second = service.getOrCreatePreferences('user-1');

      expect(first.id).toBe(second.id);
      expect(repo.count()).toBe(1);
    });

    it('should generate sequential IDs', () => {
      const prefs1 = service.getOrCreatePreferences('user-1');
      const prefs2 = service.getOrCreatePreferences('user-2');

      expect(prefs1.id).toBe('pref-0001');
      expect(prefs2.id).toBe('pref-0002');
    });
  });

  describe('updateEmailPreferences', () => {
    it('should disable email notifications', () => {
      service.getOrCreatePreferences('user-1');
      const updated = service.updateEmailPreferences('user-1', {
        enabled: false,
      });

      expect(updated.email.enabled).toBe(false);
      // Other fields unchanged
      expect(updated.email.frequency).toBe('immediate');
      expect(updated.email.categories.orders).toBe(true);
    });

    it('should update frequency', () => {
      service.getOrCreatePreferences('user-1');
      const updated = service.updateEmailPreferences('user-1', {
        frequency: 'daily-digest',
      });

      expect(updated.email.frequency).toBe('daily-digest');
      expect(updated.email.enabled).toBe(true);
    });

    it('should update individual categories', () => {
      service.getOrCreatePreferences('user-1');
      const updated = service.updateEmailPreferences('user-1', {
        categories: { orders: false },
      });

      expect(updated.email.categories.orders).toBe(false);
      expect(updated.email.categories.account).toBe(true);
      expect(updated.email.categories.system).toBe(true);
    });

    it('should update multiple fields at once', () => {
      service.getOrCreatePreferences('user-1');
      const updated = service.updateEmailPreferences('user-1', {
        frequency: 'weekly-digest',
        categories: { system: false, account: false },
      });

      expect(updated.email.frequency).toBe('weekly-digest');
      expect(updated.email.categories.system).toBe(false);
      expect(updated.email.categories.account).toBe(false);
      expect(updated.email.categories.orders).toBe(true);
    });

    it('should create preferences if they do not exist', () => {
      const updated = service.updateEmailPreferences('user-1', {
        enabled: false,
      });

      expect(updated.userId).toBe('user-1');
      expect(updated.email.enabled).toBe(false);
    });

    it('should persist updates', () => {
      service.getOrCreatePreferences('user-1');
      service.updateEmailPreferences('user-1', { enabled: false });

      const retrieved = service.getPreferences('user-1');
      expect(retrieved!.email.enabled).toBe(false);
    });
  });

  describe('updateSmsPreferences', () => {
    it('should disable SMS notifications', () => {
      service.getOrCreatePreferences('user-1');
      const updated = service.updateSmsPreferences('user-1', {
        enabled: false,
      });

      expect(updated.sms!.enabled).toBe(false);
      expect(updated.sms!.categories.orders).toBe(true);
    });

    it('should update individual SMS categories', () => {
      service.getOrCreatePreferences('user-1');
      const updated = service.updateSmsPreferences('user-1', {
        categories: { orders: false },
      });

      expect(updated.sms!.categories.orders).toBe(false);
      expect(updated.sms!.categories.account).toBe(true);
      expect(updated.sms!.categories.system).toBe(true);
    });

    it('should not affect email preferences when updating SMS', () => {
      service.getOrCreatePreferences('user-1');
      service.updateSmsPreferences('user-1', { enabled: false });

      const prefs = service.getPreferences('user-1');
      expect(prefs!.email.enabled).toBe(true);
      expect(prefs!.sms!.enabled).toBe(false);
    });

    it('should create preferences if they do not exist', () => {
      const updated = service.updateSmsPreferences('user-1', {
        enabled: false,
      });

      expect(updated.userId).toBe('user-1');
      expect(updated.sms!.enabled).toBe(false);
      // Email defaults should still be created
      expect(updated.email.enabled).toBe(true);
    });

    it('should persist SMS updates', () => {
      service.getOrCreatePreferences('user-1');
      service.updateSmsPreferences('user-1', { enabled: false });

      const retrieved = service.getPreferences('user-1');
      expect(retrieved!.sms!.enabled).toBe(false);
    });
  });

  describe('updateWebhookPreferences', () => {
    it('should disable webhook notifications', () => {
      service.getOrCreatePreferences('user-1');
      const updated = service.updateWebhookPreferences('user-1', {
        enabled: false,
      });

      expect(updated.webhook!.enabled).toBe(false);
      expect(updated.webhook!.categories.orders).toBe(true);
    });

    it('should update individual webhook categories', () => {
      service.getOrCreatePreferences('user-1');
      const updated = service.updateWebhookPreferences('user-1', {
        categories: { system: false },
      });

      expect(updated.webhook!.categories.system).toBe(false);
      expect(updated.webhook!.categories.orders).toBe(true);
      expect(updated.webhook!.categories.account).toBe(true);
    });

    it('should not affect other channels when updating webhook', () => {
      service.getOrCreatePreferences('user-1');
      service.updateWebhookPreferences('user-1', { enabled: false });

      const prefs = service.getPreferences('user-1');
      expect(prefs!.email.enabled).toBe(true);
      expect(prefs!.sms!.enabled).toBe(true);
      expect(prefs!.webhook!.enabled).toBe(false);
    });
  });

  describe('shouldNotify', () => {
    it('should allow notifications when no preferences exist (default opt-in)', () => {
      expect(service.shouldNotify('user-1', 'order-confirmation', 'email')).toBe(true);
    });

    it('should allow notifications when email is enabled', () => {
      service.getOrCreatePreferences('user-1');
      expect(service.shouldNotify('user-1', 'order-confirmation', 'email')).toBe(true);
    });

    it('should suppress notifications when email is disabled', () => {
      service.getOrCreatePreferences('user-1');
