    });

    it('should suppress order notifications when orders category is disabled', () => {
      service.getOrCreatePreferences('user-1');
      service.updateEmailPreferences('user-1', {
        categories: { orders: false },
      });

      expect(service.shouldNotify('user-1', 'order-confirmation', 'email')).toBe(false);
      expect(service.shouldNotify('user-1', 'order-status-update', 'email')).toBe(false);
      // Account and system still allowed
      expect(service.shouldNotify('user-1', 'user-welcome', 'email')).toBe(true);
      expect(service.shouldNotify('user-1', 'system-alert', 'email')).toBe(true);
    });

    it('should suppress account notifications when account category is disabled', () => {
      service.getOrCreatePreferences('user-1');
      service.updateEmailPreferences('user-1', {
        categories: { account: false },
      });

      expect(service.shouldNotify('user-1', 'user-welcome', 'email')).toBe(false);
      expect(service.shouldNotify('user-1', 'user-updated', 'email')).toBe(false);
      expect(service.shouldNotify('user-1', 'order-confirmation', 'email')).toBe(true);
    });

    it('should suppress system notifications when system category is disabled', () => {
      service.getOrCreatePreferences('user-1');
      service.updateEmailPreferences('user-1', {
        categories: { system: false },
      });

      expect(service.shouldNotify('user-1', 'system-alert', 'email')).toBe(false);
      expect(service.shouldNotify('user-1', 'order-confirmation', 'email')).toBe(true);
    });

    it('should allow in-app channel by default (no preferences defined for it)', () => {
      service.getOrCreatePreferences('user-1');
      service.updateEmailPreferences('user-1', { enabled: false });

      expect(service.shouldNotify('user-1', 'order-confirmation', 'in-app')).toBe(true);
    });

    // SMS channel preference checks
    it('should suppress SMS notifications when SMS is disabled', () => {
      service.getOrCreatePreferences('user-1');
      service.updateSmsPreferences('user-1', { enabled: false });

      expect(service.shouldNotify('user-1', 'order-confirmation', 'sms')).toBe(false);
    });

    it('should suppress SMS notifications for disabled categories', () => {
      service.getOrCreatePreferences('user-1');
      service.updateSmsPreferences('user-1', {
        categories: { orders: false },
      });

      expect(service.shouldNotify('user-1', 'order-confirmation', 'sms')).toBe(false);
      expect(service.shouldNotify('user-1', 'user-welcome', 'sms')).toBe(true);
    });

    it('should allow SMS notifications when SMS is enabled', () => {
      service.getOrCreatePreferences('user-1');
      expect(service.shouldNotify('user-1', 'order-confirmation', 'sms')).toBe(true);
    });

    // Webhook channel preference checks
    it('should suppress webhook notifications when webhook is disabled', () => {
      service.getOrCreatePreferences('user-1');
      service.updateWebhookPreferences('user-1', { enabled: false });

      expect(service.shouldNotify('user-1', 'order-confirmation', 'webhook')).toBe(false);
