    it('should allow disabling email while keeping SMS and webhook enabled', () => {
      service.getOrCreatePreferences('user-1');
      service.updateEmailPreferences('user-1', { enabled: false });

      expect(service.shouldNotify('user-1', 'order-confirmation', 'email')).toBe(false);
